import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"老舍纪念馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/laoshe.md","filePath":"museums/laoshe.md","lastUpdated":null}'),o={name:"museums/laoshe.md"};function i(d,t,n,s,h,u){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="老舍纪念馆" tabindex="-1">老舍纪念馆 <a class="header-anchor" href="#老舍纪念馆" aria-label="Permalink to &quot;老舍纪念馆&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1599577170594-50c2845c7f12?w=1200" alt="老舍纪念馆"></p><blockquote><p>&quot;生活是种律动，须有光有影，有左有右，有晴有雨，滋味就含在这变而不猛的曲折里。&quot; —— 老舍《小病》</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>老舍纪念馆位于北京市东城区灯市口西街丰富胡同19号，是老舍先生1950年至1966年在北京的故居。这是一座典型的北京四合院，老舍先生在这里度过了人生的最后16年。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁5号线灯市口站A口</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">微信公众号&quot;老舍纪念馆&quot;</td></tr></tbody></table><h2 id="老舍与北京" tabindex="-1">老舍与北京 <a class="header-anchor" href="#老舍与北京" aria-label="Permalink to &quot;老舍与北京&quot;">​</a></h2><h3 id="北京情结" tabindex="-1">北京情结 <a class="header-anchor" href="#北京情结" aria-label="Permalink to &quot;北京情结&quot;">​</a></h3><p>老舍（1899-1966），原名舒庆春，满族正红旗人。他是中国现代小说家、作家、语言大师、人民艺术家。</p><p>老舍对北京有着深厚的感情，他的作品中充满了对北京风土人情的描写：</p><ul><li>《茶馆》：北京老茶馆里的人情冷暖</li><li>《四世同堂》：抗战时期北京小羊圈胡同的故事</li><li>《骆驼祥子》：人力车夫祥子的命运</li><li>《龙须沟》：解放前后北京龙须沟的变化</li></ul><h3 id="在故居的岁月" tabindex="-1">在故居的岁月 <a class="header-anchor" href="#在故居的岁月" aria-label="Permalink to &quot;在故居的岁月&quot;">​</a></h3><p>1950年，老舍从美国讲学归来，购得此院。在这里，他度过了创作最丰富的时期：</p><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1951年</td><td style="text-align:left;">创作《龙须沟》，获&quot;人民艺术家&quot;称号</td></tr><tr><td style="text-align:left;">1956年</td><td style="text-align:left;">创作《茶馆》</td></tr><tr><td style="text-align:left;">1966年</td><td style="text-align:left;">文革开始，8月24日投湖自尽</td></tr></tbody></table><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><p>老舍纪念馆是一座典型的老北京四合院，占地约500平方米。</p><h3 id="展室分布" tabindex="-1">展室分布 <a class="header-anchor" href="#展室分布" aria-label="Permalink to &quot;展室分布&quot;">​</a></h3><ul><li><strong>第一展室（正房）</strong>：展示老舍的生平与创作历程</li><li><strong>第二展室（东厢房）</strong>：展示老舍的生活用品和家庭照片</li><li><strong>第三展室（西厢房）</strong>：展示老舍的代表作品和手稿</li></ul><h3 id="后院" tabindex="-1">后院 <a class="header-anchor" href="#后院" aria-label="Permalink to &quot;后院&quot;">​</a></h3><p>后院种植着老舍生前喜爱的花木，有两棵太平花是老舍亲手栽种的。</p><h2 id="珍贵藏品" tabindex="-1">珍贵藏品 <a class="header-anchor" href="#珍贵藏品" aria-label="Permalink to &quot;珍贵藏品&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">藏品</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">老舍手稿</td><td style="text-align:left;">《正红旗下》等作品原稿</td></tr><tr><td style="text-align:left;">齐白石画</td><td style="text-align:left;">《蛙声十里出山泉》等</td></tr><tr><td style="text-align:left;">生活用品</td><td style="text-align:left;">眼镜、毛笔、茶具等</td></tr><tr><td style="text-align:left;">剧照</td><td style="text-align:left;">《茶馆》《龙须沟》首演照片</td></tr><tr><td style="text-align:left;">藏书</td><td style="text-align:left;">约2500册</td></tr></tbody></table><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="老舍-笔名的由来" tabindex="-1">&quot;老舍&quot;笔名的由来 <a class="header-anchor" href="#老舍-笔名的由来" aria-label="Permalink to &quot;&quot;老舍&quot;笔名的由来&quot;">​</a></h3><p>老舍原名舒庆春，他把&quot;舒&quot;字拆开，取&quot;舍&quot;和&quot;予&quot;，寓意&quot;舍弃自我&quot;。</p><h3 id="《茶馆》的诞生" tabindex="-1">《茶馆》的诞生 <a class="header-anchor" href="#《茶馆》的诞生" aria-label="Permalink to &quot;《茶馆》的诞生&quot;">​</a></h3><p>1956年，老舍在故居完成了话剧《茶馆》的创作。这部剧被誉为&quot;东方舞台上的奇迹&quot;，至今仍是北京人艺的保留剧目。</p><h3 id="人民艺术家" tabindex="-1">人民艺术家 <a class="header-anchor" href="#人民艺术家" aria-label="Permalink to &quot;人民艺术家&quot;">​</a></h3><p>1951年，北京市人民政府授予老舍&quot;人民艺术家&quot;的荣誉称号，老舍成为新中国第一位获得这一称号的作家。</p><h3 id="最后的岁月" tabindex="-1">最后的岁月 <a class="header-anchor" href="#最后的岁月" aria-label="Permalink to &quot;最后的岁月&quot;">​</a></h3><p>1966年文化大革命开始，老舍受到冲击。8月24日，老舍独自走出家门，来到北京太平湖畔，投湖自尽，享年67岁。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="参观顺序" tabindex="-1">参观顺序 <a class="header-anchor" href="#参观顺序" aria-label="Permalink to &quot;参观顺序&quot;">​</a></h3><ol><li><strong>第一展室</strong>：了解老舍生平</li><li><strong>第二展室</strong>：观看生活用品</li><li><strong>第三展室</strong>：欣赏代表作品</li><li><strong>后院</strong>：在太平花下驻足</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th></tr></thead><tbody><tr><td style="text-align:left;">王府井大街</td><td style="text-align:center;">500米</td></tr><tr><td style="text-align:left;">中国美术馆</td><td style="text-align:center;">1公里</td></tr><tr><td style="text-align:left;">北大红楼</td><td style="text-align:center;">1.5公里</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：老舍纪念馆虽小，但处处透着书香气息。在这里，你能感受到老舍对北京的热爱，以及他作品中那份浓浓的京味儿。</p>',39)])])}const f=e(o,[["render",i]]);export{x as __pageData,f as default};
